using System;
using System.Collections.Generic;
using Eplan.EplApi.Base;
using Eplan.EplApi.DataModel;
using Eplan.EplApi.DataModel.E3D;

namespace EplanScripting
{
    [StartUp]
    public class CreateTransientArea
    {
        [EplAction(Name = "Create Transient Area", Description = "Creates a transient area and displays its size.")]
        public void CreateArea()
        {
            try
            {
                // Get the active project
                Project project = Project.ActiveProject;

                if (project == null)
                {
                    MessageBox.Show("No project is currently open.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }

                // Define the size of the area
                PointD areaSize = new PointD(100, 50);

                // Define the function definition (Area definition)
                FunctionDefinition functionDefinition = null;
                foreach (FunctionDefinition def in project.FunctionDefinitions)
                {
                    if (def.Category == FunctionCategory.AreaDefinition)
                    {
                        functionDefinition = def;
                        break;
                    }
                }

                if (functionDefinition == null)
                {
                    MessageBox.Show("No Area Definition Function Definition found in the project.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }

                // Create the transient area
                Area transientArea = Area.CreateTransient(project, functionDefinition, areaSize);

                if (transientArea != null)
                {
                    // Get the size of the area
                    PointD retrievedSize = transientArea.Size;

                    // Display the size of the area
                    MessageBox.Show($"Transient Area Size: Width = {retrievedSize.X}, Height = {retrievedSize.Y}", "Information", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                else
                {
                    MessageBox.Show("Failed to create transient area.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            catch (ArgumentNullException ex)
            {
                MessageBox.Show($"ArgumentNullException: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            catch (WrongCategoryException ex)
            {
                MessageBox.Show($"WrongCategoryException: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            catch (ObjectCreationException ex)
            {
                MessageBox.Show($"ObjectCreationException: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            catch (Exception ex)
            {
                MessageBox.Show($"An unexpected error occurred: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
    }
}
