public class BackupProjectScript
{
    [Eplan.EplApi.EService.EService( "My.BackupProject" )]
    public void Start()
    {
        try
        {
            // Create a new Backup object.
            Backup oBackup = new Backup();

            // Define the project path.
            string projectPath = "$(MD_PROJECTS)\\MyProject.elk"; // Replace with your project's path

            // Define the comment for the backup.
            string comment = "Backup created by script";

            // Define the target path for the backup.
            string targetPath = "$(MD_PROJECTS)"; // Replace with your desired backup directory

            // Define the archive name for the backup.
            string archiveName = "MyProject_backup.zw1"; // Replace with your desired backup file name

            // Define if referenced data should be copied automatically.
            bool automaticallyCopyReferencedData = true;

            // Call the Project method to perform the backup.
            // MakeBackup: Project is backed up
            oBackup.Project(
                projectPath,
                comment,
                targetPath,
                archiveName,
                Backup.Type.MakeBackup,
                automaticallyCopyReferencedData
            );

            // Display a success message.
            Console.WriteLine("Project backup created successfully!");
        }
        catch (Eplan.EplApi.Base.BaseException e)
        {
            // Handle any exceptions that occur during the backup process.
            Console.WriteLine($"An error occurred: {e.Message}");
            // Optionally, log the exception details.
            Console.WriteLine(e.StackTrace);
        }
        catch (ApplicationException e)
        {
            // Handle application-specific exceptions.
            Console.WriteLine($"An application error occurred: {e.Message}");
            Console.WriteLine(e.StackTrace);
        }
        catch (Exception e)
        {
            // Handle any other unexpected exceptions.
            Console.WriteLine($"An unexpected error occurred: {e.Message}");
            Console.WriteLine(e.StackTrace);
        }
    }
}
