using System;
using Eplan.EplApi.Base;
using Eplan.EplApi.DataModel;

namespace EplanScripting
{
    [StartUp]
    public class GetFunctionWeight
    {
        [Eplan.EplApi.Base.EService(Eplan.EplApi.Base.EService.EType.eAction, Eplan.EplApi.Base.EService.EVisibility.ePublic, true)]
        public void GetWeight(string functionName)
        {
            try
            {
                // Get the project from the current application
                Project project = new Project(Eplan.EplApi.Base.Settings.ProjectName);

                // Find the function by its name
                Function function = FindFunctionByName(project, functionName);

                if (function != null)
                {
                    // Get the property list for the function
                    UniversalPropertyList propertyList = function.PropertyList;

                    // Get the value of the FUNC_ARTICLE_WEIGHT_ITEM property
                    PropertyValue propertyValue = propertyList.GetPropertyValue(Placement3DPropertyList.FUNC_ARTICLE_WEIGHT_ITEM());

                    if (propertyValue != null)
                    {
                        // Display the weight value
                        double weight = Convert.ToDouble(propertyValue.Value);
                        MessageBox.Show($"The weight of function '{functionName}' is: {weight}");
                    }
                    else
                    {
                        MessageBox.Show($"The property FUNC_ARTICLE_WEIGHT_ITEM was not found for function '{functionName}'.");
                    }
                }
                else
                {
                    MessageBox.Show($"Function '{functionName}' not found in the project.");
                }
            }
            catch (Exception ex)
            {
                MessageBox.Show($"An error occurred: {ex.Message}");
            }
        }

        private Function FindFunctionByName(Project project, string functionName)
        {
            // Iterate through all the pages in the project
            foreach (Page page in project.Pages)
            {
                // Iterate through all the objects on the page
                foreach (Object obj in page.Objects)
                {
                    // Check if the object is a function
                    if (obj is Function)
                    {
                        Function function = (Function)obj;
                        // Check if the function name matches the search criteria
                        if (function.Name == functionName)
                        {
                            return function;
                        }
                    }
                }
            }
            return null;
        }
    }
}
