    {
        try
        {
            // Create a new Connection3D object
            Connection3D connection3D = new Connection3D();

            // Create the connection using the Create method, specifying start and end placements and connection point indices
            connection3D.Create(startPlacement, startIndex, endPlacement, endIndex);

            // Optionally, add some logging or confirmation here
            Console.WriteLine("3D Connection created successfully.");
        }
        catch (BaseException ex)
        {
            // Handle any exceptions that occur during the process
            Console.WriteLine("Error creating 3D connection: " + ex.Message);
        }
    }

    [EplAction(Caption = "Create 3D Connection", Category = "Custom")]
    public void Run()
    {
        // Get the active project
        Project project = new ProjectManager().GetActiveProject();

        if (project == null)
        {
            MessageBox.Show("Please open a project first.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return;
        }

        // Replace these with actual Placement3D objects and connection point indices
        // This is a placeholder, you'll need to get these from your project data
        // Example:  Assuming you have two Function3D objects, get their placements and connection point indices
        // You'll need to adapt this part to your specific project structure
        Placement3D startPlacement = null;
        short startIndex = -1;
        Placement3D endPlacement = null;
        short endIndex = -1;

        // Example: Get the first two Function3D objects and their placements
        foreach (Page page in project.Pages)
        {
            foreach (Function3D function in page.Functions)
            {
                if (startPlacement == null)
                {
                    startPlacement = function.Placement3D;
                    if (startPlacement != null && startPlacement.ConnectionPointPositions.Length > 0)
                    {
                        startIndex = startPlacement.ConnectionPointPositions[0].Index;
                    }
                }
                else if (endPlacement == null)
                {
                    endPlacement = function.Placement3D;
                    if (endPlacement != null && endPlacement.ConnectionPointPositions.Length > 0)
                    {
                        endIndex = endPlacement.ConnectionPointPositions[0].Index;
                    }
                }
                if (startPlacement != null && endPlacement != null)
                {
                    break;
                }
            }
            if (startPlacement != null && endPlacement != null)
            {
                break;
            }
        }

        if (startPlacement == null || endPlacement == null)
        {
            MessageBox.Show("Could not find two Function3D objects in the project. Please ensure there are 3D functions in the project.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return;
        }

        // Call the Execute method to create the connection
        Execute(project, startPlacement, startIndex, endPlacement, endIndex);
    }
}
