    public void SetMaterial(string projectName, string connectionPointName, string material)
    {
        try
        {
            // Open the project
            using (Project project = new Project(projectName))
            {
                // Get the connection definition point
                var connectionDefinitionPoints = project.FindObjects<ConnectionDefinitionPoint>(x => x.Name == connectionPointName);

                if (connectionDefinitionPoints.Count > 0)
                {
                    ConnectionDefinitionPoint connectionDefinitionPoint = connectionDefinitionPoints[0];

                    // Get the ConnectionDefinitionPointPropertyList
                    ConnectionDefinitionPointPropertyList propertyList = connectionDefinitionPoint.Properties;

                    // Set the material
                    propertyList.ARTICLE_MATERIAL = material;

                    // Store the changes
                    connectionDefinitionPoint.StoreToObject();

                    MessageBox.Show("Material set successfully.");
                }
                else
                {
                    MessageBox.Show("Connection definition point not found.");
                }
            }
