using System;
using Eplan.EplApi.Base;
using Eplan.EplApi.DataModel;
using Eplan.EplApi.HEServices;

public class ExportPageToPdf
{
    [Start]
    public void Run(string projectPath, string pageName, string outputPath, string colorSetting, bool usePrintMargins)
    {
        try
        {
            // 1. Initialize EPLAN application
            using (var app = new Eplan.EplApi.System.EplApplication())
            {
                app.Init(""); // Initialize EPLAN

                // 2. Get the project
                Project project = new Project(projectPath);

                // 3. Get the page
                Page page = project.Pages.Find(pageName);

                if (page == null)
                {
                    throw new ArgumentException($"Page '{pageName}' not found in project.");
                }

                // 4. Determine color setting
                Export.DegreeOfColor color;
                switch (colorSetting.ToLower())
                {
                    case "blackandwhite":
                        color = Export.DegreeOfColor.BlackAndWhite;
                        break;
                    case "greylevel":
                        color = Export.DegreeOfColor.GreyLevel;
                        break;
                    case "color":
                        color = Export.DegreeOfColor.Color;
                        break;
                    default:
                        color = Export.DegreeOfColor.Color; // Default to color
                        break;
                }

                // 5. Create an Export object
                using (var export = new Export())
                {
                    // 6. Export the page to PDF
                    export.PdfPages(new System.Collections.ArrayList() { page }, "", outputPath, color, false, "", usePrintMargins);

                    // 7. Display a success message
                    MessageManager.ShowInformation("Page exported to PDF successfully.");
                }
            }
        }
        catch (Exception ex)
        {
            // 8. Handle exceptions
            MessageManager.ShowError(ex.Message);
        }
    }
}
