        {
            // Get the project and open it.
            ProjectManager projectManager = new ProjectManager();
            Project project = projectManager.OpenProject("C:\\EPLAN\\MyProject.elk"); // Replace with your project path

            // Get the first location box in the project.
            LocationBox locationBox = GetFirstLocationBox(project);

            if (locationBox != null)
            {
                // Get the properties of the location box.
                LocationBoxPropertyList properties = locationBox.Properties;

                // Get the description property (LOCATION_DESCRIPTION).
                PropertyValue descriptionValue = properties.LOCATION_DESCRIPTION;

                // Check if the description property has a value.
                if (descriptionValue != null)
                {
                    // Get the description as a MultiLangString.
                    MultiLangString description = (MultiLangString)descriptionValue;

                    // Print the description to the console.
                    Console.WriteLine("Location Box Description: " + description.ToString());
                }
                else
                {
                    Console.WriteLine("Location Box Description: No description found.");
                }
            }
            else
            {
                Console.WriteLine("No Location Box found in the project.");
            }

            // Close the project.
            project.Close();
        }
        catch (Exception ex)
        {
            Console.WriteLine("Error: " + ex.Message);
        }
    }

    // Helper function to get the first location box in the project.
    private static LocationBox GetFirstLocationBox(Project project)
    {
        foreach (Page page in project.Pages)
        {
            foreach (var placement in page.Placements)
            {
                if (placement is LocationBox)
                {
                    return (LocationBox)placement;
                }
            }
        }
        return null;
    }
}
