            // Find the mounting panel by name (assuming it's a 3D object)
            StorableObject mountingPanel = FindMountingPanelByName(project, mountingPanelName);

            if (mountingPanel == null)
            {
                Message.Error($"Mounting panel '{mountingPanelName}' not found.");
                return false;
            }

            // Access the properties of the mounting panel
            MountingPanelPropertyList properties = new MountingPanelPropertyList(mountingPanel);

            // Get the value of the DESIGNATION_FULLFUNCTIONALASSIGNMENT property
            PropertyValue propertyValue = properties.DESIGNATION_FULLFUNCTIONALASSIGNMENT();

            // Check if the property value is not null
            if (propertyValue != null)
            {
                // Display the value
                string functionalAssignment = propertyValue.ToString();
                Message.Info($"Functional Assignment for '{mountingPanelName}': {functionalAssignment}");
            }
            else
            {
                Message.Info($"Functional Assignment for '{mountingPanelName}' is not set.");
            }

            return true;
        }
        catch (Exception ex)
        {
            Message.Error("An error occurred: " + ex.Message);
            return false;
        }
    }

    private StorableObject FindMountingPanelByName(Project project, string mountingPanelName)
    {
        // Iterate through all objects in the project
        foreach (StorableObject obj in project.Objects)
        {
            // Check if the object is a mounting panel and its name matches
            if (obj is MountingPanel && obj.Name == mountingPanelName)
            {
                return obj;
            }
        }
        return null;
    }
}
