    {
        try
        {
            // Get the active project
            Project project = new Project(Project.ActiveProject); // Use ActiveProject to get the currently open project

            // Check if a project is open
            if (project == null || string.IsNullOrEmpty(project.Name))
            {
                MessageDlg.Show("No project is currently open.", "Error", MessageBoxButtons.Ok, MessageBoxIcon.Error);
                return;
            }

            // Define the page where the PlugStrip will be placed.  Replace with your desired page name and type.
            string pageName = "=A1-1"; // Example page name
            PageType pageType = PageType.Schematic; // Example page type

            // Find the page
            Page page = null;
            foreach (Page p in project.Pages)
            {
                if (p.Name == pageName && p.PageType == pageType)
                {
                    page = p;
                    break;
                }
            }

            // If the page is not found, create a new page
            if (page == null)
            {
                page = new Page(project);
                page.Name = pageName;
                page.PageType = pageType;
                // You might want to set other page properties here, like page size.
