    public void CreatePolylineAction()
    {
        try
        {
            // Get the active project
            Project project = new Project(Project.GetProjectInfo().ProjectName);

            // Check if a project is open
            if (project == null || string.IsNullOrEmpty(project.ProjectName))
            {
                Message.Show("Please open a project first.", "Create PolyLine", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            // Get the first page of the project
            Page page = project.Pages.GetEnumerator().Current;

            // Check if a page exists
            if (page == null)
            {
                Message.Show("No pages found in the project.", "Create PolyLine", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            // Create a new PolyLine object
            PolyLine polyLine = new PolyLine();

            // Create the PolyLine on the page
            polyLine.Create(page);

            // Define the points for the polyline
            PointD point1 = new PointD(10, 10);
            PointD point2 = new PointD(20, 20);
            PointD point3 = new PointD(30, 10);

            // Set the points for the polyline
            polyLine.SetPointAt(0, ref point1);
            polyLine.SetPointAt(1, ref point2);
            polyLine.SetPointAt(2, ref point3);

            // Set the polyline to be closed
            polyLine.Closed = true;

            // Set the fill pattern
            polyLine.FillPattern = GraphicalPlacement.FillPatternType.Solid;

            // Store the changes to the database
            page.Store();

