    [Eplan.EplApi.EServices.ActionAttribute("Create and Open Project", "Creates a new project from a template and opens it in exclusive mode.")]
    public void Execute()
    {
        try
        {
            // Get the ProjectManager instance.
            ProjectManager projectManager = new ProjectManager();

            // Define the project path and template path.
            string projectPath = projectManager.Paths.Projects + "\\MyNewProject.elk";
            string templatePath = projectManager.Paths.Templates + "\\YourTemplate.ept"; // Replace with your template file.

            // Check if the template file exists.
            if (!System.IO.File.Exists(templatePath))
            {
                System.Windows.Forms.MessageBox.Show("Template file not found: " + templatePath, "Error", System.Windows.Forms.MessageBoxButtons.OK, System.Windows.Forms.MessageBoxIcon.Error);
                return;
            }

            // Create the project using the template.
            Project newProject = projectManager.CreateProject(projectPath, templatePath);

            // Check if project creation was successful
            if (newProject == null)
            {
                System.Windows.Forms.MessageBox.Show("Failed to create project.", "Error", System.Windows.Forms.MessageBoxButtons.OK, System.Windows.Forms.MessageBoxIcon.Error);
                return;
            }

            // Open the project in exclusive mode.
            Project openedProject = projectManager.OpenProject(projectPath, ProjectManager.OpenMode.Exclusive);

            // Check if the project was opened successfully.
            if (openedProject != null)
            {
                System.Windows.Forms.MessageBox.Show("Project created and opened successfully in exclusive mode.", "Success", System.Windows.Forms.MessageBoxButtons.OK, System.Windows.Forms.MessageBoxIcon.Information);
            }
            else
            {
