        {
            System.Windows.Forms.MessageBox.Show("Project opening failed: " + ex.Message, "Error", System.Windows.Forms.MessageBoxButtons.OK, System.Windows.Forms.MessageBoxIcon.Error);
        }
        catch (ArgumentException ex)
